const safeMigrate = async () => {
    // 1. Backup the problematic table temporarily
    await db.execute(`CREATE TABLE tasks_backup AS SELECT * FROM tasks`);

    // 2. Run the rebuild with FK protection
    await db.execute(`PRAGMA foreign_keys = ON;`); // Keep FKs ON during rebuild

    // 3. The rebuild will now respect cascades properly
    // (This may require testing as it changes behavior)
};
```

