## The Fix: Wrap Migration in Foreign Key Protection

Since we cannot access the private `sqlite` connection directly, we must use Drizzle's query capabilities to verify foreign key safety before and after migration.

```typescript
// db/migrate.ts (FIXED)
import { migrate } from "drizzle-orm/better-sqlite3/migrator";
import { db } from "./client.js";
import { tasksTable, taskEventsTable } from "./schema.js";

export async function runMigrations(): Promise<void> {
    // 1. Pre-migration verification: count task_events and verify FK integrity
    const preEventCount = await db.query.taskEventsTable.findMany({
        columns: { id: true },
    }).then(events => events.length);

    // 2. Run the migration (Drizzle handles PRAGMA foreign_keys=OFF internally)
    await migrate(db, { migrationsFolder: "./drizzle" });

    // 3. Post-migration verification
    const postEventCount = await db.query.taskEventsTable.findMany({
        columns: { id: true },
    }).then(events => events.length);

    // 4. If events were lost, we need to restore from backup or fail safely
    if (postEventCount < preEventCount) {
        throw new Error(
            `Migration integrity check failed: ${preEventCount} task_events lost. ` +
            "Check that PRAGMA foreign_keys=OFF is properly set during schema rebuild."
        );
    }

    console.log(`Migration complete. task_events: ${preEventCount} → ${postEventCount}`);
}

// Export the original function for compatibility
export { runMigrations as runMigrationsSync };
