export function withForeignKeySafety<T>(fn: () => Promise<T>): Promise<T> {
    return (async () => {
        try {
            // Disable FK enforcement only for the critical path
            sqlite.pragma("foreign_keys = OFF");
            try {
                return await fn();
            } finally {
                sqlite.pragma("foreign_keys = ON");
            }
        } catch (error) {
            // Re-enable FK enforcement on error to prevent corruption
            sqlite.pragma("foreign_keys = ON");
            throw error;
        }
    })();
}

